#include <stdio.h>
#include <stdbool.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M, Q; scanf("%d %d %d", &N, &M, &Q);
        bool *inside = (bool*)calloc(N + 1, sizeof(bool));
        int cur = 0;
        int consistent = 1;
        for (int k = 0; k < Q; ++k) {
            char op; int id;
            scanf(" %c %d", &op, &id);
            if (!consistent) continue; // still read input
            if (op == '+') {
                if (inside[id]) { consistent = 0; }
                else {
                    inside[id] = true;
                    ++cur;
                    if (cur > M) consistent = 0;
                }
            } else { // '-'
                if (!inside[id]) { consistent = 0; }
                else {
                    inside[id] = false;
                    --cur;
                }
            }
        }
        free(inside);
        printf(consistent ? "Consistent\n" : "Inconsistent\n");
    }
    return 0;
}

