#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); Q = int(next(it))
        inside = [False] * (N + 1)
        cur = 0
        ok = True
        for __ in range(Q):
            op = next(it)
            pid = int(next(it))
            if not ok:
                continue
            if op == '+':
                if inside[pid]:
                    ok = False
                else:
                    inside[pid] = True
                    cur += 1
                    if cur > M:
                        ok = False
            else:  # '-'
                if not inside[pid]:
                    ok = False
                else:
                    inside[pid] = False
                    cur -= 1
        out_lines.append('Consistent' if ok else 'Inconsistent')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

